INSERT INTO email_translations (template_key, lang, greeting, body, sign_off) VALUES
('business_legit', 'cs', 'Dobrý den,', 'Děkujeme za Váš zájem o spolupráci s LiquiMixer. Vaši nabídku jsme zaznamenali a náš tým ji posoudí. Pokud bude relevantní, ozveme se Vám do 5 pracovních dnů.', 'S pozdravem,'),
('business_legit', 'sk', 'Dobrý deň,', 'Ďakujeme za Váš záujem o spoluprácu s LiquiMixer. Vašu ponuku sme zaznamenali a náš tím ju posúdi. Ak bude relevantná, ozveme sa Vám do 5 pracovných dní.', 'S pozdravom,'),
('business_legit', 'en', 'Dear Sir/Madam,', 'Thank you for your interest in collaborating with LiquiMixer. We have recorded your offer and our team will review it. If it is relevant, we will get back to you within 5 business days.', 'Best regards,'),
('business_legit', 'de', 'Sehr geehrte Damen und Herren,', 'Vielen Dank für Ihr Interesse an einer Zusammenarbeit mit LiquiMixer. Wir haben Ihr Angebot registriert und unser Team wird es prüfen. Sollte es relevant sein, melden wir uns innerhalb von 5 Werktagen bei Ihnen.', 'Mit freundlichen Grüßen,'),
('business_legit', 'fr', 'Madame, Monsieur,', 'Merci pour votre intérêt à collaborer avec LiquiMixer. Nous avons enregistré votre offre et notre équipe l''examinera. Si elle est pertinente, nous vous recontacterons dans les 5 jours ouvrables.', 'Cordialement,'),
('business_legit', 'es', 'Estimado/a,', 'Gracias por su interés en colaborar con LiquiMixer. Hemos registrado su oferta y nuestro equipo la revisará. Si es relevante, nos pondremos en contacto con usted en un plazo de 5 días hábiles.', 'Atentamente,'),
('business_legit', 'it', 'Gentile Signore/Signora,', 'Grazie per il suo interesse a collaborare con LiquiMixer. Abbiamo registrato la sua offerta e il nostro team la esaminerà. Se sarà rilevante, la contatteremo entro 5 giorni lavorativi.', 'Cordiali saluti,'),
('business_legit', 'pt', 'Prezado(a),', 'Obrigado pelo seu interesse em colaborar com a LiquiMixer. Registramos sua oferta e nossa equipe a analisará. Se for relevante, entraremos em contato em até 5 dias úteis.', 'Atenciosamente,'),
('business_legit', 'pl', 'Szanowni Państwo,', 'Dziękujemy za zainteresowanie współpracą z LiquiMixer. Zarejestrowaliśmy Państwa ofertę i nasz zespół ją oceni. Jeśli będzie odpowiednia, skontaktujemy się w ciągu 5 dni roboczych.', 'Z poważaniem,'),
('business_legit', 'nl', 'Geachte heer/mevrouw,', 'Bedankt voor uw interesse in samenwerking met LiquiMixer. We hebben uw aanbod geregistreerd en ons team zal het beoordelen. Als het relevant is, nemen we binnen 5 werkdagen contact met u op.', 'Met vriendelijke groet,'),
('business_legit', 'tr', 'Sayın yetkili,', 'LiquiMixer ile işbirliği konusundaki ilginize teşekkür ederiz. Teklifinizi kaydettik ve ekibimiz inceleyecektir. Uygun olması halinde 5 iş günü içinde sizinle iletişime geçeceğiz.', 'Saygılarımla,'),
('business_legit', 'ru', 'Уважаемые,', 'Благодарим вас за интерес к сотрудничеству с LiquiMixer. Мы зафиксировали ваше предложение и наша команда его рассмотрит. Если оно будет актуальным, мы свяжемся с вами в течение 5 рабочих дней.', 'С уважением,'),
('business_legit', 'hu', 'Tisztelt Hölgyem/Uram,', 'Köszönjük érdeklődésüket a LiquiMixerrel való együttműködés iránt. Rögzítettük ajánlatukat és csapatunk át fogja tekinteni. Ha releváns, 5 munkanapon belül felkeressük Önöket.', 'Tisztelettel,'),
('business_legit', 'ro', 'Stimate,', 'Vă mulțumim pentru interesul dumneavoastră de a colabora cu LiquiMixer. Am înregistrat oferta dumneavoastră și echipa noastră o va analiza. Dacă este relevantă, vă vom contacta în termen de 5 zile lucrătoare.', 'Cu stimă,'),
('business_legit', 'uk', 'Шановні,', 'Дякуємо за ваш інтерес до співпраці з LiquiMixer. Ми зареєстрували вашу пропозицію і наша команда її розгляне. Якщо вона буде актуальною, ми зв''яжемося з вами протягом 5 робочих днів.', 'З повагою,'),
('business_legit', 'sv', 'Hej,', 'Tack för ert intresse av samarbete med LiquiMixer. Vi har registrerat ert erbjudande och vårt team kommer att granska det. Om det är relevant återkommer vi inom 5 arbetsdagar.', 'Med vänliga hälsningar,'),
('business_legit', 'da', 'Hej,', 'Tak for jeres interesse i samarbejde med LiquiMixer. Vi har registreret jeres tilbud og vores team vil gennemgå det. Hvis det er relevant, vender vi tilbage inden for 5 hverdage.', 'Med venlig hilsen,'),
('business_legit', 'fi', 'Hei,', 'Kiitos kiinnostuksestanne yhteistyöhön LiquiMixerin kanssa. Olemme kirjanneet tarjouksenne ja tiimimme arvioi sen. Jos se on relevantti, otamme yhteyttä 5 työpäivän kuluessa.', 'Ystävällisesti,'),
('business_legit', 'no', 'Hei,', 'Takk for deres interesse for samarbeid med LiquiMixer. Vi har registrert tilbudet deres og teamet vårt vil vurdere det. Hvis det er relevant, tar vi kontakt innen 5 virkedager.', 'Med vennlig hilsen,'),
('business_legit', 'ja', 'ご担当者様、', 'LiquiMixerとのコラボレーションにご関心をお寄せいただきありがとうございます。ご提案を記録し、チームがレビューいたします。該当する場合は、5営業日以内にご連絡いたします。', '敬具、'),
('business_legit', 'ko', '담당자님께,', 'LiquiMixer와의 협업에 관심을 가져주셔서 감사합니다. 귀하의 제안을 기록했으며 저희 팀이 검토할 것입니다. 관련이 있을 경우 5영업일 이내에 연락드리겠습니다.', '감사합니다,'),
('business_legit', 'ar', 'السيدات والسادة الأفاضل،', 'شكراً لاهتمامكم بالتعاون مع LiquiMixer. لقد سجلنا عرضكم وسيقوم فريقنا بمراجعته. إذا كان ذا صلة، سنعاود الاتصال بكم خلال 5 أيام عمل.', 'مع التحيات،')
